router.post(
  "/webhooks/stripe",
  import_express.default.raw({ type: "application/json" }),
  async (req, res) => {
    try {
      const signature = req.headers["stripe-signature"];
      if (!signature) {
        return res.status(400).json({ error: "No signature" });
      }
      const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET || "";
      let event;
      try {
        event = getStripe().webhooks.constructEvent(
          req.body,
          signature,
          webhookSecret
        );
      } catch (err) {
        console.error("Webhook signature verification failed:", err);
        return res.status(400).json({ error: "Invalid signature" });
      }
      if (event.type === "checkout.session.completed") {
        const session = event.data.object;
        const customerEmail = session.customer_email || session.customer_details?.email;
        const customerName = session.customer_details?.name || null;
        const stripeCustomerId = session.customer;
        const paymentIntentId = session.payment_intent;
        const amountTotal = session.amount_total || 0;
        const productId = session.metadata?.product_id;
        const productName = session.metadata?.product_name;
        if (!customerEmail || !productId || !productName) {
          console.error("Missing required data from Stripe session");
          return res.status(400).json({ error: "Missing data" });
        }
        let user;
        try {
          user = await getUserByEmail(customerEmail);
          if (!user) {
            user = await createUser(customerEmail, stripeCustomerId, customerName || void 0);
            console.log(`Created new user: ${user.id} (${customerName || "no name"})`);
          } else if (customerName && !user.name) {
            user = await updateUserName(user.id, customerName);
            if (user) console.log(`Updated user name: ${customerName}`);
          }
        } catch (error) {
          user = await createUser(customerEmail, stripeCustomerId, customerName || void 0);
          console.log(`Created new user: ${user.id} (${customerName || "no name"})`);
        }
        if (!user) throw new Error("Not a portal user");
        await createPurchase(
          user.id,
          productId,
          productName,
          amountTotal / 100,
          paymentIntentId
        );
        console.log(`Purchase recorded for user ${user.id}: ${productName}`);
        const baseUrl2 = process.env.REPL_SLUG ? `https://${process.env.REPL_SLUG}.${process.env.REPL_OWNER}.repl.co` : "http://localhost:5000";
        const magicLink = await generateMagicLink(
          customerEmail,
          user.id,
          baseUrl2
        );
        console.log(`Magic link for ${customerEmail}: ${magicLink}`);
        const { quizUsers: quizUsers2 } = await Promise.resolve().then(() => (init_schema2(), schema_exports));
        const [quizUser] = await db.select().from(quizUsers2).where(eq(quizUsers2.email, customerEmail));
        await sendPurchaseConfirmationEmail({
          email: customerEmail,
          firstName: customerName?.split(" ")[0] || void 0,
          patternName: quizUser?.primaryPattern || null,
          productName,
          portalLink: magicLink
        });
      }
      res.json({ received: true });
    } catch (error) {
      console.error("Webhook error:", error);
      res.status(500).json({ error: "Webhook processing failed" });
    }
  }
);
